__CPROVER_requires(__CPROVER_forall { size_t m; (m < lz77->size) ==> (lz77->dists[m] == 0 || lz77->d_symbol[m] < ZOPFLI_NUM_D) })
__CPROVER_requires(__CPROVER_forall {
    size_t t; (lstart <= t && t < lend) ==>
        (lz77->litlens[t] <= 258 &&
         (lz77->dists[t] == 0 ||
          (lz77->litlens[t] >= 3 && lz77->dists[t] <= 32768))) })
