/* For an empty window the stored-block cost is exactly 0, while the fixed
   (>= 3) and dynamic (>= 29) encodings always cost more; the stored cost is
   thus the strict minimum and the chosen result is exactly 0.  This pins both
   conjunction branches of the selection test: any mutant that diverts the
   empty-window case into the min(fixed, dyn) branch returns a positive value
   and is killed. */
__CPROVER_ensures(lstart == lend ==> __CPROVER_return_value == 0)
/* Every encoding pays at least the 3 header bits, so their minimum does too. */
__CPROVER_ensures(lstart != lend ==> __CPROVER_return_value >= 3)
// clang-format on
{
    double uncompressedcost = ZopfliCalculateBlockSize(lz77, lstart, lend, 0);
    /* Don't do the expensive fixed cost calculation for larger blocks that are
       unlikely to use it. */
    double fixedcost = (lz77->size > 1000) ? uncompressedcost : ZopfliCalculateBlockSize(lz77, lstart, lend, 1);
    double dyncost = ZopfliCalculateBlockSize(lz77, lstart, lend, 2);
    return (uncompressedcost < fixedcost && uncompressedcost < dyncost)
               ? uncompressedcost
               : (fixedcost < dyncost ? fixedcost : dyncost);
}

/*
Returns estimated cost of a block in bits.  It includes the size to encode the
tree and the size to encode all literal, length and distance symbols and their
extra bits.

litlens: lz77 lit/lengths
dists: ll77 distances
lstart: start of block
lend: end of block (not inclusive)
*/
static double EstimateCost(const ZopfliLZ77Store *lz77,
                           size_t lstart, size_t lend)
{
    return ZopfliCalculateBlockSizeAutoType(lz77, lstart, lend);
}

/*
Gets the cost which is the sum of the cost of the left and the right section
of the data.
type: FindMinimumFun
*/
static double SplitCost(size_t i, void *context)
{
    SplitCostContext *c = (SplitCostContext *)context;
    return EstimateCost(c->lz77, c->start, i) + EstimateCost(c->lz77, i, c->end);
